# skeptic-checked S41-T1-A-E2
def assess(record: dict) -> str:
    required = {"case_id", "method", "resource", "created", "status"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (record["method"] == "POST" and record["status"] == 201 and record.get("created") is True) else "RETURN_CORRECT_HTTP_STATUS"

valid = {"case_id": "CASO-ARE-041-1A", **{"method":"POST","resource":"/v1/jobs","created":True,"status":201}}
invalid = {**valid, **{"status": 200, "method": "GET"}}
incomplete = {k: v for k, v in valid.items() if k != "status"}
print(assess(valid), assess(invalid), assess(incomplete))

